1687 Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
1688                                                 bool FoldWithMultiUse) {
1689   // Don't modify shared select instructions unless set FoldWithMultiUse
1690   if (!SI->hasOneUse() && !FoldWithMultiUse)
1691     return nullptr;
1692 
1693   Value *TV = SI->getTrueValue();
1694   Value *FV = SI->getFalseValue();
1695   if (!(isa<Constant>(TV) || isa<Constant>(FV)))
1696     return nullptr;
1697 
1698   // Bool selects with constant operands can be folded to logical ops.
1699   if (SI->getType()->isIntOrIntVectorTy(1))
1700     return nullptr;
1701 
1702   // Test if a FCmpInst instruction is used exclusively by a select as
1703   // part of a minimum or maximum operation. If so, refrain from doing
1704   // any other folding. This helps out other analyses which understand
1705   // non-obfuscated minimum and maximum idioms. And in this case, at
1706   // least one of the comparison operands has at least one user besides
1707   // the compare (the select), which would often largely negate the
1708   // benefit of folding anyway.
